import{c as a,Q as t,j as r,m as l}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"ハーネスエンジニアリングは枠組みから始めよう","description":"","frontmatter":{"title":"ハーネスエンジニアリングは枠組みから始めよう","date":"2026-04-01T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-01-start-harness-engineering-caddi.md","filePath":"research/ai-articles/scored/2026-04-01-start-harness-engineering-caddi.md","lastUpdated":1779894392000}'),o={name:"research/ai-articles/scored/2026-04-01-start-harness-engineering-caddi.md"};function d(i,e,s,n,h,c){return t(),r("div",null,[...e[0]||(e[0]=[l('<blockquote><p>Source: <a href="https://caddi.tech/start-harness-engineering-with-framework" target="_blank" rel="noreferrer">https://caddi.tech/start-harness-engineering-with-framework</a> Fetched: 2026-05-08</p></blockquote><h1 id="ハーネスエンジニアリングは枠組みから始めよう" tabindex="-1">ハーネスエンジニアリングは枠組みから始めよう <a class="header-anchor" href="#ハーネスエンジニアリングは枠組みから始めよう" aria-label="Permalink to &quot;ハーネスエンジニアリングは枠組みから始めよう&quot;">​</a></h1><h2 id="はじめに" tabindex="-1">はじめに <a class="header-anchor" href="#はじめに" aria-label="Permalink to &quot;はじめに&quot;">​</a></h2><p>本記事は、CADDiで Quote というアプリケーション開発に携わるエンジニアが、ハーネスエンジニアリングの実装を通じた学習を記しています。</p><h2 id="この記事のゴール" tabindex="-1">この記事のゴール <a class="header-anchor" href="#この記事のゴール" aria-label="Permalink to &quot;この記事のゴール&quot;">​</a></h2><p>著者の目標は「完璧なハーネスを最初から作り込まなきゃ」という心理的障壁を取り除くことです。「&quot;とりあえず枠組みを作って、チームで育てていく&quot;という発想」を共有し、気軽にハーネス整備を開始できる状態を作ることを重視しています。</p><h2 id="ハーネス整備のハードル" tabindex="-1">ハーネス整備のハードル <a class="header-anchor" href="#ハーネス整備のハードル" aria-label="Permalink to &quot;ハーネス整備のハードル&quot;">​</a></h2><p>開発では、コーディングエージェントの出力品質が期待を下回る場面が多かったそうです。毎回「コードから自明なコメントは不要」といった指摘をしていましたが、実装ガイドラインが十分に整備されていませんでした。</p><p>複数の心理的障壁がありました：</p><ul><li>チーム間での認識統一の必要性</li><li>ルール整備形式についての事前議論</li><li>ルールファイルと実装PRの分離検討</li></ul><p>最終的に Rules ファイルの整備に着手し、バックエンドの実装ルールを <code>.claude/rules/</code> ディレクトリに配置しました。</p><h2 id="claude-code-の-rules-について" tabindex="-1">Claude Code の Rules について <a class="header-anchor" href="#claude-code-の-rules-について" aria-label="Permalink to &quot;Claude Code の Rules について&quot;">​</a></h2><p>Claude Code には <code>CLAUDE.md</code> に指示を書く仕組みがありますが、量が増えると管理が困難になります。Rules システムでは <code>.claude/rules/</code> ディレクトリの Markdown ファイルでトピック別に分割管理できます。</p><p>YAML frontmatter の <code>paths</code> で特定ファイルパスを指定すると、条件付きルール（conditional rules）として機能します。例えば API 関連ファイルを扱う際のみ特定ルールが読み込まれます。</p><p>ルールは汎用ルール（レイヤー横断）とレイヤー別実装ルールに大別されます。</p><h2 id="ルール整備によって変わったこと" tabindex="-1">ルール整備によって変わったこと <a class="header-anchor" href="#ルール整備によって変わったこと" aria-label="Permalink to &quot;ルール整備によって変わったこと&quot;">​</a></h2><p>ルール整備後、実装中に「これもルールに盛り込みたい」という点が出現しました。そこでルール更新用スキル <code>/update-coding-rule</code> を作成しました。</p><p>このスキルにより、実装中の細かい指摘をコマンド一つで品質基準に反映できるようになりました。PR レビューコメント URL を渡すことで、該当スレッドを取得してルール化することも可能です。</p><h2 id="なぜうまくいったのか-枠組みの力" tabindex="-1">なぜうまくいったのか：枠組みの力 <a class="header-anchor" href="#なぜうまくいったのか-枠組みの力" aria-label="Permalink to &quot;なぜうまくいったのか：枠組みの力&quot;">​</a></h2><p>重要な気づきとして、ルール整備が成功した理由は「充実したルールファイル」ではなく、「どこに・どんな形で置くか」という枠組みの存在でした。</p><p>形式が決まっていると、更新ハードルが大幅に低下します。「これはここに追加すればいい」という道筋が見えることが、内容の充実度よりも重要でした。</p><h2 id="始め方-枠組みだけ先に作る" tabindex="-1">始め方：枠組みだけ先に作る <a class="header-anchor" href="#始め方-枠組みだけ先に作る" aria-label="Permalink to &quot;始め方：枠組みだけ先に作る&quot;">​</a></h2><p>著者の経験では、1日かけてルール全体を整備しましたが、それは不要でした。ほぼ空のルールファイル群だけで十分です。</p><p>提供されるプロンプト例では、プロジェクトアーキテクチャを分析し、Rules ファイルの骨組みを Claude Code に生成させています。</p><p>ルールドキュメントは2種類に大別されます：</p><ol><li><strong>汎用ルール</strong>：レイヤー横断の共通方針（例：coding-style.md、testing.md）</li><li><strong>レイヤー別ルール</strong>：各レイヤーのサブディレクトリに実装・テストルール分離（例：usecase/usecase.md）</li></ol><p>各ドキュメントには概要セクションを設け、目的を明示します。</p><h2 id="インデックスファイルの構成" tabindex="-1">インデックスファイルの構成 <a class="header-anchor" href="#インデックスファイルの構成" aria-label="Permalink to &quot;インデックスファイルの構成&quot;">​</a></h2><p><code>.claude/rules/</code> は&quot;インデックス&quot;として扱い、ルール本体への参照のみを記載します。frontmatter の <code>paths</code> で対象ファイルを指定し、本文でルール本体へのパスを記載します。</p><p>この構成により、conditional rules 読み込み時のトークン数を最小化しながら、必要に応じて詳細ルールにアクセスできます。</p><h2 id="rules-以外にも枠組みは作れる" tabindex="-1">Rules 以外にも枠組みは作れる <a class="header-anchor" href="#rules-以外にも枠組みは作れる" aria-label="Permalink to &quot;Rules 以外にも枠組みは作れる&quot;">​</a></h2><p>同じ発想は他の要素にも応用できます：</p><ul><li><strong>Skills</strong>：最小限の機能で API stub 生成スキルを用意し、使用中にフィードバックを集める</li><li><strong>Hooks</strong>：各タイミング用の専用スクリプトを配置し、段階的に充実させる</li></ul><p>「枠組みと責務が明確だと、更新・拡張のハードルが下がる」という原則は共通しています。</p><h2 id="終わりに" tabindex="-1">終わりに <a class="header-anchor" href="#終わりに" aria-label="Permalink to &quot;終わりに&quot;">​</a></h2><p>ハーネスエンジニアリングは完璧な設計から始まるものではありません。内容がスカスカでも、「ここに足していける」という場所があれば、チーム内での気づきを反映できるようになります。</p><p>開発とハーネス整備を区別せず、同じタスクで完結させることで、ハーネスは自然に成長していきます。</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><p><strong>原文語言</strong>：日文（日本 CADDi 工程師分享 Harness Engineering 實作經驗）</p><h3 id="核心命題-從框架開始-不求完美" tabindex="-1">核心命題：從框架開始，不求完美 <a class="header-anchor" href="#核心命題-從框架開始-不求完美" aria-label="Permalink to &quot;核心命題：從框架開始，不求完美&quot;">​</a></h3><p>最大的心理障礙是「覺得要完美設計才能開始」。正確的心態是：<strong>先建立框架，讓團隊共同培育</strong>——輕鬆開始 harness 整備比一次建好更重要。</p><h3 id="常見的心理障礙" tabindex="-1">常見的心理障礙 <a class="header-anchor" href="#常見的心理障礙" aria-label="Permalink to &quot;常見的心理障礙&quot;">​</a></h3><ul><li>需要統一團隊認知</li><li>需要事先討論規則整備形式</li><li>需要考慮規則檔與實作 PR 的分離</li></ul><p>最終行動：著手整備 Rules 檔案，將後端實作規則放置在 <code>.claude/rules/</code> 目錄。</p><h3 id="claude-code-rules-系統" tabindex="-1">Claude Code Rules 系統 <a class="header-anchor" href="#claude-code-rules-系統" aria-label="Permalink to &quot;Claude Code Rules 系統&quot;">​</a></h3><ul><li><code>CLAUDE.md</code> 隨內容增加而難以管理 → Rules 系統允許在 <code>.claude/rules/</code> 按主題分割管理</li><li>YAML frontmatter 的 <code>paths</code> 指定特定檔案路徑 → <strong>Conditional Rules</strong>（條件式規則）：例如只在處理 API 相關檔案時載入特定規則</li><li>兩大類規則：<strong>汎用規則</strong>（跨層通用方針）+ <strong>層別實作規則</strong>（各層的實作/測試規則）</li></ul><h3 id="update-coding-rule-skill-即時反饋閉環" tabindex="-1"><code>/update-coding-rule</code> Skill：即時反饋閉環 <a class="header-anchor" href="#update-coding-rule-skill-即時反饋閉環" aria-label="Permalink to &quot;`/update-coding-rule` Skill：即時反饋閉環&quot;">​</a></h3><p>整備規則後，實作中會出現「這也想加進規則」的情況。作者建立了規則更新用 skill：</p><ul><li>一個指令就能將實作中的細微指摘反映到品質基準</li><li>傳入 PR review 評論 URL → 取得該討論串 → 直接規則化</li></ul><h3 id="框架的力量-「放在哪裡」比「放什麼」更重要" tabindex="-1">框架的力量：「放在哪裡」比「放什麼」更重要 <a class="header-anchor" href="#框架的力量-「放在哪裡」比「放什麼」更重要" aria-label="Permalink to &quot;框架的力量：「放在哪裡」比「放什麼」更重要&quot;">​</a></h3><p>成功的關鍵洞見：規則整備成功的原因不是「豐富的規則檔案」，而是「<strong>決定放在哪裡、用什麼形式放</strong>」這個框架的存在。</p><p>形式一旦確定：</p><ul><li>更新門檻大幅下降</li><li>「這個加在這裡就好」的路徑清晰</li><li>內容的充實程度比框架的存在更次要</li></ul><h3 id="實際建立方式" tabindex="-1">實際建立方式 <a class="header-anchor" href="#實際建立方式" aria-label="Permalink to &quot;實際建立方式&quot;">​</a></h3><p><strong>從幾乎空的規則檔案開始就足夠</strong>——用 prompt 讓 Claude Code 分析專案架構，生成 Rules 檔案的骨架。</p><p>規則文件分類：</p><ol><li><strong>汎用規則</strong>：coding-style.md、testing.md（跨層共通方針）</li><li><strong>層別規則</strong>：各層的子目錄分別放實作規則 + 測試規則</li></ol><p>Index 檔案設計：<code>.claude/rules/</code> 作為「索引」，只記載到規則本體的參照，最小化 conditional rules 載入時的 token 數。</p><h3 id="同樣原則適用-skills-和-hooks" tabindex="-1">同樣原則適用 Skills 和 Hooks <a class="header-anchor" href="#同樣原則適用-skills-和-hooks" aria-label="Permalink to &quot;同樣原則適用 Skills 和 Hooks&quot;">​</a></h3><ul><li><strong>Skills</strong>：先準備最小功能的 API stub 生成 skill，在使用中蒐集反饋</li><li><strong>Hooks</strong>：各時機的專用 script 先配置好，再逐步充實</li></ul><p>「框架和職責清楚 → 更新/擴充門檻下降」是共通原則。</p><h3 id="核心哲學" tabindex="-1">核心哲學 <a class="header-anchor" href="#核心哲學" aria-label="Permalink to &quot;核心哲學&quot;">​</a></h3><p>開發與 harness 整備不分離——在<strong>同一個任務中完結</strong>，harness 就會自然成長。完美設計不是開始的前提，「這裡可以加東西」的確定感才是。</p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>7/10</td><td>CLAUDE.md 設置、conditional rules with globs、/update-coding-rule skill 均可直接採用</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>「心理障礙」概念、「框架優先於內容」洞見、開發與 harness 不分離哲學新穎</td></tr><tr><td>C. 證據品質</td><td>6/10</td><td>定性說明為主；缺乏量化數據</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>每個 harness 元素有具體說明，但較入門層級</td></tr><tr><td>E. 泛化性</td><td>7/10</td><td>入門框架普遍適用；不限特定 agent 工具</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.8/10</strong></td><td>7×0.3+7×0.2+6×0.2+7×0.15+7×0.15 = 2.1+1.4+1.2+1.05+1.05</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/rules/core.md</code>（「框架優先於內容」原則補充）<br><strong>整合狀態</strong>：待實作</p>',68)])])}const g=a(o,[["render",d]]);export{p as __pageData,g as default};
